import{_ as e,o,c as i,ag as t}from"./chunks/framework.CTpQozEL.js";const b=JSON.parse('{"title":"Peekaboo 브리지","description":"macOS UI 자동화를 위한 PeekabooBridge 통합","frontmatter":{"title":"Peekaboo 브리지","description":"macOS UI 자동화를 위한 PeekabooBridge 통합"},"headers":[],"relativePath":"platforms/mac/peekaboo.md","filePath":"platforms/mac/peekaboo.md","lastUpdated":null}'),l={name:"platforms/mac/peekaboo.md"};function s(r,a,n,p,d,c){return o(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="peekaboo-브리지-macos-ui-자동화" tabindex="-1">Peekaboo 브리지 (macOS UI 자동화) <a class="header-anchor" href="#peekaboo-브리지-macos-ui-자동화" aria-label="Permalink to &quot;Peekaboo 브리지 (macOS UI 자동화)&quot;">​</a></h1><p>OpenClaw는 <strong>PeekabooBridge</strong>를 로컬 권한 인식 UI 자동화 브로커로 호스팅할 수 있습니다. 이를 통해 <code>peekaboo</code> CLI가 macOS 앱의 TCC 권한을 재사용하면서 UI 자동화를 구동할 수 있습니다.</p><h2 id="이것이-무엇인지-그리고-무엇이-아닌지" tabindex="-1">이것이 무엇인지 (그리고 무엇이 아닌지) <a class="header-anchor" href="#이것이-무엇인지-그리고-무엇이-아닌지" aria-label="Permalink to &quot;이것이 무엇인지 (그리고 무엇이 아닌지)&quot;">​</a></h2><ul><li><strong>호스트</strong>: OpenClaw.app은 PeekabooBridge 호스트 역할을 할 수 있습니다.</li><li><strong>클라이언트</strong>: <code>peekaboo</code> CLI를 사용합니다 (별도의 <code>openclaw ui ...</code> 표면 없음).</li><li><strong>UI</strong>: 시각적 오버레이는 Peekaboo.app에 유지됩니다. OpenClaw는 얇은 브로커 호스트입니다.</li></ul><h2 id="브리지-활성화" tabindex="-1">브리지 활성화 <a class="header-anchor" href="#브리지-활성화" aria-label="Permalink to &quot;브리지 활성화&quot;">​</a></h2><p>macOS 앱에서:</p><ul><li>설정 → <strong>Enable Peekaboo Bridge</strong></li></ul><p>활성화되면 OpenClaw는 로컬 UNIX 소켓 서버를 시작합니다. 비활성화되면 호스트가 중지되고 <code>peekaboo</code>는 다른 사용 가능한 호스트로 대체됩니다.</p><h2 id="클라이언트-검색-순서" tabindex="-1">클라이언트 검색 순서 <a class="header-anchor" href="#클라이언트-검색-순서" aria-label="Permalink to &quot;클라이언트 검색 순서&quot;">​</a></h2><p>Peekaboo 클라이언트는 일반적으로 이 순서로 호스트를 시도합니다:</p><ol><li>Peekaboo.app (전체 UX)</li><li>Claude.app (설치된 경우)</li><li>OpenClaw.app (얇은 브로커)</li></ol><p><code>peekaboo bridge status --verbose</code>를 사용하여 어떤 호스트가 활성 상태이고 어떤 소켓 경로가 사용 중인지 확인합니다. 다음으로 재정의할 수 있습니다:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> PEEKABOO_BRIDGE_SOCKET</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/path/to/bridge.sock</span></span></code></pre></div><h2 id="보안-및-권한" tabindex="-1">보안 및 권한 <a class="header-anchor" href="#보안-및-권한" aria-label="Permalink to &quot;보안 및 권한&quot;">​</a></h2><ul><li>브리지는 <strong>발신자 코드 서명</strong>을 검증합니다. TeamID의 허용 목록이 시행됩니다 (Peekaboo 호스트 TeamID + OpenClaw 앱 TeamID).</li><li>요청은 ~10초 후 타임아웃됩니다.</li><li>필요한 권한이 없는 경우 브리지는 System Settings를 시작하는 대신 명확한 오류 메시지를 반환합니다.</li></ul><h2 id="스냅샷-동작-자동화" tabindex="-1">스냅샷 동작 (자동화) <a class="header-anchor" href="#스냅샷-동작-자동화" aria-label="Permalink to &quot;스냅샷 동작 (자동화)&quot;">​</a></h2><p>스냅샷은 메모리에 저장되고 짧은 시간 후 자동으로 만료됩니다. 더 오래 보유해야 하는 경우 클라이언트에서 다시 캡처하십시오.</p><h2 id="문제-해결" tabindex="-1">문제 해결 <a class="header-anchor" href="#문제-해결" aria-label="Permalink to &quot;문제 해결&quot;">​</a></h2><ul><li><code>peekaboo</code>가 &quot;bridge client is not authorized&quot;를 보고하면 클라이언트가 올바르게 서명되어 있는지 확인하거나 <strong>디버그</strong> 모드에서만 <code>PEEKABOO_ALLOW_UNSIGNED_SOCKET_CLIENTS=1</code>로 호스트를 실행하십시오.</li><li>호스트가 없으면 호스트 앱 중 하나 (Peekaboo.app 또는 OpenClaw.app)를 열고 권한이 부여되었는지 확인하십시오.</li></ul>',19)])])}const k=e(l,[["render",s]]);export{b as __pageData,k as default};
